const express = require('express');
const multer = require('multer');
const { getKeywords, addData } = require('../models/dataModel');
const { formatResponse } = require('../../utils/helpers');
const db = require('../../config/database');

const router = express.Router();

// Configuration de multer pour gérer les uploads
const upload = multer({ dest: 'uploads/' }); // Les fichiers sont stockés dans le dossier "uploads"

// Récupérer les mots-clés correspondant à une recherche
router.get('/keywords', async (req, res) => {
  try {
    const query = req.query.search || '';
    db.all(
      SELECT * FROM keywords WHERE keyword LIKE ?,
      [%${query}%],
      (err, rows) => {
        if (err) {
          res.json(formatResponse(500, null, 'Erreur lors de la récupération des mots-clés.'));
        } else {
          res.json(formatResponse(200, rows));
        }
      }
    );
  } catch (err) {
    res.json(formatResponse(500, null, 'Erreur inattendue.'));
  }
});

// Ajouter une donnée avec des tags et un fichier
router.post('/data', upload.single('file'), async (req, res) => {
  try {
    const { name, data, tags } = req.body;
    const file = req.file; // Fichier téléversé

    // Validation des entrées
    if (!name && !file) {
      return res.json(formatResponse(400, null, 'Le nom ou un fichier est obligatoire.'));
    }

    // Conversion des tags en tableau si nécessaire
    const tagList = Array.isArray(tags) ? tags : tags ? tags.split(',') : [];

    db.run(
      INSERT INTO datas (name, data) VALUES (?, ?),
      [name, data || (file ? file.path : null)],
      function (err) {
        if (err) {
          res.json(formatResponse(500, null, 'Erreur lors de l\'ajout des données.'));
        } else {
          const dataId = this.lastID;

          // Ajouter les mots-clés et les associer à la donnée
          tagList.forEach((tag) => {
            db.run(
              INSERT OR IGNORE INTO keywords (keyword) VALUES (?),
              [tag],
              function (err) {
                if (err) {
                  console.error(Erreur lors de l'ajout du mot-clé "${tag}":, err.message);
                } else {
                  const keywordId = this.lastID || null;
                  db.run(
                    INSERT INTO dataKeyword (dataId, keywordId) VALUES (?, ?),
                    [dataId, keywordId],
                    (err) => {
                      if (err) {
                        console.error(
                          Erreur lors de l'association de la donnée "${dataId}" avec le mot-clé "${tag}":,
                          err.message
                        );
                      }
                    }
                  );
                }
              }
            );
          });

          res.json(formatResponse(201, { id: dataId }, 'Donnée ajoutée avec succès.'));
        }
      }
    );
  } catch (err) {
    res.json(formatResponse(500, null, 'Erreur inattendue.'));
  }
});

