  }
};

// Ajouter un tag à la sélection dans la modal
modalSuggestionsDiv.addEventListener('click', (e) => {
  if (e.target && e.target.classList.contains('tag-suggestion')) {
    const tag = e.target.textContent;
    if (!modalSelectedTags.includes(tag)) {
      modalSelectedTags.push(tag);
      updateModalSelectedTags();
    }
  }
});

// Mettre à jour l'affichage des tags sélectionnés dans la modal
const updateModalSelectedTags = () => {
  modalSelectedTagsDiv.innerHTML = modalSelectedTags
    .map((tag) => `<span class="tag">${tag}</span>`)
    .join('');
};

// Valider les données et envoyer à l’API
validateDataButton.addEventListener('click', async () => {
  const name = dataNameInput.value.trim();
  const content = dataContentInput.value.trim();
