2. Modification de l’API top-tags
Dans votre fichier dataRoutes.js ou équivalent, modifiez la route /api/top-tags pour qu’elle accepte une liste de tags en paramètre. Si des tags sont fournis, elle renvoie les tags les plus fréquemment associés aux tags sélectionnés.
javascriptCopierModifierrouter.get('/top-tags', async (req, res) => {
  try {
    const tags = req.query.tags ? req.query.tags.split(',') : [];
    const defaultLimit = 5;

    let query = `
      SELECT k.keyword, COUNT(dk.dataId) AS usage_count
      FROM keywords k
      LEFT JOIN dataKeyword dk ON k.id = dk.keywordId
    `;
    let params = [];

    if (tags.length > 0) {
      query += `
        WHERE dk.dataId IN (
          SELECT dk.dataId
          FROM dataKeyword dk
          JOIN keywords k ON dk.keywordId = k.id
          WHERE k.keyword IN (${tags.map(() => '?').join(',')})
        )
      `;
      params = tags;
    }

    query += `
      GROUP BY k.id
      ORDER BY usage_count DESC
      LIMIT ?
    `;
    params.push(defaultLimit);

    db.all(query, params, (err, rows) => {
      if (err) {
        return res.json({
          status: 500,
          data: null,
          message: 'Erreur lors de la récupération des tags.',
        });
      }
      res.json({ status: 200, data: rows });
    });
  } catch (err) {
    res.json({ status: 500, data: null, message: 'Erreur inattendue.' });
  }
});


