Étape 1 : Création du module tags.js
Ajoutez un fichier tags.js dans le répertoire services pour définir le module.
javascriptCopierModifierexport class TagsModule {
  constructor(config) {
    this.selectedTags = [];
    this.inputElement = config.inputElement;
    this.suggestionsContainer = config.suggestionsContainer;
    this.topTagsContainer = config.topTagsContainer;
    this.selectedTagsContainer = config.selectedTagsContainer;
    this.apiEndpoints = config.apiEndpoints;

    this.initialize();
  }

  initialize() {
    this.setupAutoComplete();
    this.loadTopTags();
  }

  async loadTopTags() {
    try {
      const response = await fetch(
        `${this.apiEndpoints.topTags}?tags=${this.selectedTags.join(',')}`
      );
      const data = await response.json();
      if (data.status === 200) {
        this.topTagsContainer.innerHTML = data.data
          .map((tag) => `<span class="tag unselected">${tag.keyword}</span>`)
          .join('');
      } else {
        console.error('Erreur lors du chargement des top tags :', data.message);
      }
    } catch (err) {
      console.error('Erreur lors de la connexion au serveur pour les top tags :', err);
    }
  }

  setupAutoComplete() {
    this.inputElement.addEventListener('input', async () => {
      const query = this.inputElement.value.trim();
      if (query.length >= 3) {
        try {
          const response = await fetch(
            `${this.apiEndpoints.keywords}?search=${query}`
          );
          const data = await response.json();
          if (data.status === 200) {
            this.suggestionsContainer.innerHTML = data.data
              .map((tag) => `<span class="tag unselected">${tag.keyword}</span>`)
              .join('');
          } else {
            this.suggestionsContainer.innerHTML = '';
            console.error('Erreur lors de la recherche de mots-clés :', data.message);
          }
        } catch (err) {
          console.error('Erreur lors de la connexion au serveur pour les suggestions :', err);
        }
      } else {
        this.suggestionsContainer.innerHTML = '';
      }
    });

    this.suggestionsContainer.addEventListener('click', (e) => {
      if (e.target && e.target.classList.contains('tag')) {
        const tag = e.target.textContent.trim();
        this.toggleTag(tag);
      }
    });

    this.topTagsContainer.addEventListener('click', (e) => {
      if (e.target && e.target.classList.contains('tag')) {
        const tag = e.target.textContent.trim();
        this.toggleTag(tag);
      }
    });
  }

  toggleTag(tag) {
    if (this.selectedTags.includes(tag)) {
      this.selectedTags = this.selectedTags.filter((t) => t !== tag);
    } else {
      this.selectedTags.push(tag);
    }
    this.updateSelectedTagsDisplay();
    this.loadTopTags();
  }

  updateSelectedTagsDisplay() {
    this.selectedTagsContainer.innerHTML = this.selectedTags
      .map((tag) => `<span class="tag selected">${tag}</span>`)
      .join('');
  }
}


