Voici un exemple complet du fichier initDatabase.js corrigé et prêt à être exécuté :
javascriptCopierModifierconst db = require('../config/database');

console.log('Démarrage du script initDatabase.js');

const createTables = () => {
  db.serialize(() => {
    console.log('Création des tables en cours...');

    // Table des mots-clés
    db.run(`
      CREATE TABLE IF NOT EXISTS keywords (
