        console.error('Erreur lors de la création de la table keywords :', err.message);
      } else {
        console.log('Table keywords créée ou déjà existante.');
      }
    });

    // Table des données
    db.run(`
      CREATE TABLE IF NOT EXISTS datas (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        name TEXT NOT NULL,
        data TEXT,
        dateAdd DATETIME DEFAULT CURRENT_TIMESTAMP
      )
    `, (err) => {
      if (err) {
        console.error('Erreur lors de la création de la table datas :', err.message);
      } else {
        console.log('Table datas créée ou déjà existante.');
      }
    });

    // Table de liaison entre données et mots-clés
    db.run(`
      CREATE TABLE IF NOT EXISTS dataKeyword (
        dataId INTEGER,
        keywordId INTEGER,
        FOREIGN KEY (dataId) REFERENCES datas(id),
        FOREIGN KEY (keywordId) REFERENCES keywords(id)
      )
    `, (err) => {
      if (err) {
        console.error('Erreur lors de la création de la table dataKeyword :', err.message);
      } else {
        console.log('Table dataKeyword créée ou déjà existante.');
      }
    });

    // Table des paramètres
    db.run(`
      CREATE TABLE IF NOT EXISTS settings (
        key TEXT PRIMARY KEY,
        value TEXT NOT NULL
      )
    `, (err) => {
      if (err) {
        console.error('Erreur lors de la création de la table settings :', err.message);
      } else {
        console.log('Table settings créée ou déjà existante.');
      }
    });

    // Ajout des paramètres par défaut
    db.run(`
      INSERT OR IGNORE INTO settings (key, value) VALUES
        ('max_displayed_suggested_tags', '5'),
        ('most_recent_limit', '3'),
        ('most_opened_limit', '10')
    `, (err) => {
      if (err) {
        console.error('Erreur lors de l\'insertion des paramètres par défaut :', err.message);
      } else {
        console.log('Paramètres par défaut ajoutés ou déjà existants.');
      }
    });

    // Table pour les statistiques d'ouverture des données
    db.run(`
      CREATE TABLE IF NOT EXISTS dataStats (
        dataId INTEGER PRIMARY KEY,
        openCount INTEGER DEFAULT 0,
        FOREIGN KEY (dataId) REFERENCES datas(id) ON DELETE CASCADE
      )
    `, (err) => {
      if (err) {
        console.error('Erreur lors de la création de la table dataStats :', err.message);
      } else {
        console.log('Table dataStats créée ou déjà existante.');
      }
    });

    console.log('Création des tables terminée.');
  });
};

// Appeler la fonction pour créer les tables
createTables();

// Fermer la connexion à la base de données
