javascriptCopierModifierconst db = require('../config/database');

const addData = ({ name, data, tags = [], filePath = null }) => {
  return new Promise((resolve, reject) => {
    if (!name || (!data && !filePath)) return reject('Le nom et un contenu ou un fichier sont obligatoires.');

    db.run(`INSERT INTO datas (name, data) VALUES (?, ?)`, [name, data || filePath], function (err) {
      if (err) return reject('Erreur lors de l\'ajout des données.');

      const dataId = this.lastID;

      const tagPromises = tags.map(
        (tag) =>
          new Promise((resolve, reject) => {
            db.run(`INSERT OR IGNORE INTO keywords (keyword) VALUES (?)`, [tag], function (err) {
              if (err) return reject(err);

              const keywordId = this.lastID || null;
              db.run(`INSERT INTO dataKeyword (dataId, keywordId) VALUES (?, ?)`, [dataId, keywordId], (err) => {
                if (err) return reject(err);
                resolve();
              });
            });
          })
      );

      Promise.all(tagPromises)
        .then(() => resolve({ id: dataId }))
        .catch(() => reject('Erreur lors de l\'association des tags.'));
    });
  });
};

module.exports = { addData };


