          (tag) =>
            `<span class="tag" onclick="addTag('${tag.keyword}')">${tag.keyword}</span>`
        )
        .join('');
    } else {
      console.error('Erreur lors du chargement des tags populaires :', data.message);
    }
  } catch (err) {
    console.error('Erreur lors de la connexion au serveur :', err);
  }
};

// Charger les données par défaut
const loadDefaultData = async () => {
  const resultsDiv = document.getElementById('results');
  try {
    const response = await fetch('/api/default-data');
    const data = await response.json();
    if (data.status === 200) {
      displayResults(data.data);
    } else {
      console.error('Erreur lors du chargement des données par défaut :', data.message);
    }
  } catch (err) {
    console.error('Erreur lors de la récupération des données par défaut :', err);
  }
};

// Afficher les résultats
const displayResults = (data) => {
  const resultsDiv = document.getElementById('results');
  if (!data || (data.recent.length === 0 && data.mostOpened.length === 0)) {
    resultsDiv.innerHTML = '<p>Aucun résultat trouvé.</p>';
    return;
  }

  let resultsHTML = '';

  // Données récentes
  if (data.recent.length > 0) {
    resultsHTML += '<h3>Données les plus récentes</h3>';
    resultsHTML += data.recent
      .map(
        (item) =>
          `<div class="result-item">
            <h4>${item.name}</h4>
            <p>${item.data || 'Aucun contenu disponible.'}</p>
          </div>`
      )
      .join('');
  }

  // Données les plus ouvertes
  if (data.mostOpened.length > 0) {
    resultsHTML += '<h3>Données les plus ouvertes</h3>';
    resultsHTML += data.mostOpened
      .map(
        (item) =>
          `<div class="result-item">
            <h4>${item.name}</h4>
            <p>${item.data || 'Aucun contenu disponible.'}</p>
          </div>`
      )
      .join('');
  }

  resultsDiv.innerHTML = resultsHTML;
};

// Ajouter un tag
const addTag = (tag) => {
  if (!selectedTags.includes(tag)) {
    selectedTags.push(tag);
    updateSelectedTags();
    searchData();
  }
};

// Supprimer un tag
const removeTag = (tag) => {
  const index = selectedTags.indexOf(tag);
  if (index > -1) {
    selectedTags.splice(index, 1);
    updateSelectedTags();
    searchData();
  }
};

// Mettre à jour l'affichage des tags sélectionnés
const updateSelectedTags = () => {
  const searchTagsDiv = document.getElementById('search-tags');
  searchTagsDiv.innerHTML = selectedTags
    .map(
      (tag) =>
        `<span class="tag selected">
          ${tag}
          <button class="remove-tag" onclick="removeTag('${tag}')">x</button>
        </span>`
    )
    .join('');
};

// Rechercher les données en fonction des tags sélectionnés
const searchData = async () => {
  const resultsDiv = document.getElementById('results');
  if (selectedTags.length === 0) {
    resultsDiv.innerHTML = '<p>Sélectionnez des tags pour voir les résultats.</p>';
    return;
  }

  try {
    const response = await fetch(`/api/search-data?tags=${selectedTags.join(',')}`);
    const data = await response.json();
    if (data.status === 200) {
      displayResults({ recent: data.data, mostOpened: [] });
    } else {
      resultsDiv.innerHTML = `<p>Erreur : ${data.message}</p>`;
    }
  } catch (err) {
    resultsDiv.innerHTML = '<p>Erreur lors de la recherche des données.</p>';
    console.error(err);
  }
};

// Configurer l'entrée de recherche
const setupSearchInput = () => {
  const searchInput = document.getElementById('search-input');
  const suggestionsDiv = document.getElementById('suggestions');

  searchInput.addEventListener('input', async () => {
    const query = searchInput.value.trim();
    if (query.length < 3) {
      suggestionsDiv.innerHTML = '';
      return;
    }

    try {
      const response = await fetch(`/api/keywords?search=${query}`);
      const data = await response.json();
      if (data.status === 200) {
        suggestionsDiv.innerHTML = data.data
          .map(
            (keyword) =>
              `<span class="tag" onclick="addTag('${keyword.keyword}')">${keyword.keyword}</span>`
          )
          .join('');
      } else {
        suggestionsDiv.innerHTML = '';
      }
    } catch (err) {
      console.error('Erreur lors de la recherche de mots-clés :', err);
    }
  });
};


