Service settingsService.js
Ajoutez un fichier settingsService.js dans le répertoire services :
javascriptCopierModifierconst db = require('../config/database');

/**
 * Met à jour la valeur d'un paramètre dans la table settings.
 * @param {string} key - Clé du paramètre à mettre à jour.
 * @param {string} value - Nouvelle valeur pour le paramètre.
 * @returns {Promise<boolean>} - Renvoie `true` si la mise à jour a réussi, sinon `false`.
 */
const updateSettingValue = (key, value) => {
  return new Promise((resolve, reject) => {
    db.run(
      'UPDATE settings SET value = ? WHERE key = ?',
      [value, key],
      function (err) {
        if (err) {
          reject(err);
        } else {
          resolve(this.changes > 0); // `this.changes` indique le nombre de lignes affectées
        }
      }
    );
  });
};

module.exports = { updateSettingValue };


