Voici une version mise à jour et complète de votre fichier, incluant des validations supplémentaires et une gestion d'erreurs améliorée :
javascriptCopierModifierconst db = require('../config/database');

/**
 * Met à jour la valeur d'un paramètre dans la table settings.
 * @param {string} key - Clé du paramètre à mettre à jour.
 * @param {string} value - Nouvelle valeur pour le paramètre.
 * @returns {Promise<boolean>} - Renvoie `true` si la mise à jour a réussi, sinon `false`.
 */
const updateSettingValue = (key, value) => {
  return new Promise((resolve, reject) => {
    // Vérifier que les paramètres sont bien définis
    if (!key || value === undefined) {
      return reject(new Error('La clé et la valeur doivent être définies.'));
    }

    db.run(
      'UPDATE settings SET value = ? WHERE key = ?',
      [value, key],
      function (err) {
        if (err) {
          console.error('Erreur SQL lors de la mise à jour du paramètre :', err.message);
          reject(err);
        } else {
          console.log(`Paramètre mis à jour : ${key} = ${value}`);
          resolve(this.changes > 0); // `this.changes` indique le nombre de lignes affectées
        }
      }
    );
  });
};

/**
 * Récupère tous les paramètres de la table settings.
 * @returns {Promise<Array>} - Renvoie une liste de tous les paramètres.
 */
const getSettings = () => {
  return new Promise((resolve, reject) => {
    db.all('SELECT key, value FROM settings', [], (err, rows) => {
      if (err) {
        console.error('Erreur SQL lors de la récupération des paramètres :', err.message);
        reject(err);
      } else {
        resolve(rows);
      }
    });
  });
};

module.exports = { updateSettingValue, getSettings };

