javascriptCopierModifierdocument.addEventListener('DOMContentLoaded', () => {
  const settingsContainer = document.getElementById('settings-container');
  const pageTagInput = document.getElementById('page-tag-input');
  const pageNameInput = document.getElementById('page-name-input');
  const pageIconInput = document.getElementById('page-icon-input');
  const addPageButton = document.getElementById('add-page-button');
  const pagesList = document.getElementById('pages-list');

  // Charger les paramètres
  const loadSettings = async () => {
    try {
      const response = await fetch('/api/settings');
      const data = await response.json();
      if (data.status === 200) {
        settingsContainer.innerHTML = data.data
          .map(
            (setting) => `
            <div class="setting-item">
              <label for="${setting.key}">${setting.name}</label>
              <input type="text" id="${setting.key}" value="${setting.value}" onchange="updateSetting('${setting.key}')" />
            </div>
          `
          )
          .join('');
      } else {
        settingsContainer.innerHTML = `<p>Erreur : ${data.message}</p>`;
      }
    } catch (err) {
      console.error('Erreur lors de la récupération des paramètres :', err);
      settingsContainer.innerHTML = '<p>Erreur lors de la récupération des paramètres.</p>';
    }
  };

  // Mettre à jour un paramètre
  window.updateSetting = async (key) => {
    const input = document.getElementById(key);
    const newValue = input.value.trim();

    try {
      const response = await fetch(`/api/settings/${key}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ value: newValue }),
      });
      const data = await response.json();
      if (data.status === 200) {
        alert('Paramètre mis à jour avec succès.');
      } else {
        alert(`Erreur : ${data.message}`);
      }
    } catch (err) {
      console.error('Erreur lors de la mise à jour du paramètre :', err);
      alert('Erreur lors de la mise à jour.');
    }
  };

  // Charger les pages
  const loadPages = async () => {
    try {
      const response = await fetch('/api/pages');
      const data = await response.json();
      if (data.status === 200) {
        pagesList.innerHTML = data.data
          .map(
            (page) => `
            <div class="page-item">
              <span>${page.pageName} (${page.tagName})</span>
              <span><i class="${page.icon}"></i></span>
            </div>
          `
          )
          .join('');
      } else {
        pagesList.innerHTML = `<p>Erreur : ${data.message}</p>`;
      }
    } catch (err) {
      console.error('Erreur lors de la récupération des pages :', err);
    }
  };

  // Ajouter une nouvelle page
  addPageButton.addEventListener('click', async () => {
    const tagName = pageTagInput.value.trim();
    const pageName = pageNameInput.value.trim();
    const pageIcon = pageIconInput.value.trim();

    if (!tagName || !pageName || !pageIcon) {
      alert('Veuillez remplir tous les champs.');
      return;
    }

    try {
      const tagResponse = await fetch(`/api/keywords?search=${tagName}`);
      const tagData = await tagResponse.json();

      if (tagData.status !== 200 || tagData.data.length === 0) {
        alert('Tag introuvable.');
        return;
      }

      const tagId = tagData.data[0].id;
      const pageIdent = pageName.toLowerCase().replace(/\s+/g, '-');

      const response = await fetch('/api/pages', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ tagId, pageName, pageIdent, icon: pageIcon }),
      });

      const data = await response.json();
      if (data.status === 201) {
        alert('Page ajoutée avec succès.');
        loadPages();
      } else {
        alert(`Erreur : ${data.message}`);
      }
    } catch (err) {
      console.error('Erreur lors de l\'ajout de la page :', err);
    }
  });

  loadSettings();
  loadPages();
});

