javascriptCopierModifierconst db = require('../config/database');

/**
 * Récupère tous les tags associés aux pages.
 * @returns {Promise<Array>} - Une liste d'objets représentant les pages.
 */
const getPageTags = () => {
  return new Promise((resolve, reject) => {
    db.all(
      `
      SELECT p.id, p.pageName, p.icon, k.keyword
      FROM pageTag p
      JOIN keywords k ON p.tagId = k.id
      `,
      [],
      (err, rows) => {
        if (err) {
          return reject(err);
        }
        resolve(rows);
      }
    );
  });
};

/**
 * Ajoute un tag en tant que page.
 * @param {number} tagId - L'identifiant du tag.
 * @param {string} pageName - Le nom de la page.
 * @param {string} icon - Le code de l'icône (FontAwesome).
 * @returns {Promise<boolean>} - Renvoie `true` si l'ajout a réussi, sinon `false`.
 */
const addPageTag = (tagId, pageName, icon) => {
  return new Promise((resolve, reject) => {
    db.run(
      `
      INSERT INTO pageTag (tagId, pageName, icon)
      VALUES (?, ?, ?)
      `,
      [tagId, pageName, icon],
      function (err) {
        if (err) {
          return reject(err);
        }
        resolve(this.changes > 0);
      }
    );
  });
};

module.exports = { getPageTags, addPageTag };

