javascriptCopierModifierexport const setupAutoComplete = (inputElement, apiUrl) => {
  if (!inputElement || typeof inputElement.addEventListener !== 'function') {
    console.error('Erreur : L\'élément fourni n\'est pas valide ou introuvable.');
    return;
  }

  // Créer un conteneur pour les suggestions
  const suggestionContainer = document.createElement('div');
  suggestionContainer.className = 'autocomplete-suggestions';
  inputElement.parentNode.insertBefore(suggestionContainer, inputElement.nextSibling);

  inputElement.addEventListener('input', async (event) => {
    const query = event.target.value.trim();
    if (query.length >= 3) {
      try {
        const response = await fetch(`${apiUrl}?search=${query}`);
        const data = await response.json();

        if (data.status === 200) {
          suggestionContainer.innerHTML = data.data
            .map((item) => `<div class="suggestion-item">${item.keyword}</div>`)
            .join('');
        } else {
          suggestionContainer.innerHTML = `<p class="error-message">Aucune suggestion trouvée</p>`;
        }
      } catch (err) {
        console.error('Erreur lors de la récupération des suggestions :', err);
        suggestionContainer.innerHTML = `<p class="error-message">Erreur lors de la récupération des suggestions</p>`;
      }
    } else {
      suggestionContainer.innerHTML = '';
    }
  });

  // Gérer la sélection des suggestions
  suggestionContainer.addEventListener('click', (e) => {
    if (e.target && e.target.classList.contains('suggestion-item')) {
      inputElement.value = e.target.textContent;
      suggestionContainer.innerHTML = ''; // Effacer les suggestions après sélection
    }
  });

  // Masquer les suggestions si on clique ailleurs
  document.addEventListener('click', (e) => {
    if (!suggestionContainer.contains(e.target) && e.target !== inputElement) {
      suggestionContainer.innerHTML = '';
    }
  });
};

