const express = require('express');
const { getSettings, updateSettingValue } = require('../../services/settingsService');
const { getPageTags, addPageTag } = require('../../services/pagesService');
const { formatResponse } = require('../../utils/helpers');

const router = express.Router();

// Route pour récupérer tous les paramètres
router.get('/settings', async (req, res) => {
  try {
    const settings = await getSettings();
    if (settings.length === 0) {
      return res.json(formatResponse(404, null, 'Aucun paramètre trouvé.'));
    }
    res.json(formatResponse(200, settings));
  } catch (err) {
    console.error('Erreur lors de la récupération des paramètres :', err.message);
    res.json(formatResponse(500, null, 'Erreur lors de la récupération des paramètres.'));
  }
});

// Route pour mettre à jour un paramètre
router.put('/settings/:key', async (req, res) => {
  const { key } = req.params;
  const { value } = req.body;

  if (!value) {
    return res.json(formatResponse(400, null, 'La valeur est obligatoire.'));
  }

  try {
    const updated = await updateSettingValue(key, value);
    if (updated) {
      res.json(formatResponse(200, { key, value }, 'Paramètre mis à jour avec succès.'));
    } else {
      res.json(formatResponse(404, null, 'Paramètre non trouvé.'));
    }
  } catch (err) {
    console.error('Erreur lors de la mise à jour du paramètre :', err.message);
    res.json(formatResponse(500, null, 'Erreur lors de la mise à jour du paramètre.'));
  }
});

// Route pour récupérer les tags des pages
router.get('/pages', async (req, res) => {
  try {
    const pages = await getPageTags();
    res.json(formatResponse(200, pages));
  } catch (err) {
    console.error('Erreur lors de la récupération des pages :', err.message);
    res.json(formatResponse(500, null, 'Erreur lors de la récupération des pages.'));
  }
});

// Route pour ajouter un nouveau tag en tant que page
router.post('/pages', async (req, res) => {
  const { tagId, pageName, icon } = req.body;

  if (!tagId || !pageName || !icon) {
    return res.json(formatResponse(400, null, 'Tous les champs sont obligatoires.'));
  }

  try {
    const added = await addPageTag(tagId, pageName, icon);
    if (added) {
      res.json(formatResponse(201, { tagId, pageName, icon }, 'Page ajoutée avec succès.'));
    } else {
      res.json(formatResponse(400, null, 'Impossible d\'ajouter la page.'));
    }
  } catch (err) {
    console.error('Erreur lors de l\'ajout de la page :', err.message);
    res.json(formatResponse(500, null, 'Erreur lors de l\'ajout de la page.'));
  }
});

// Route temporaire pour tester la table settings
router.get('/settings/test', async (req, res) => {
  try {
    const settings = await getSettings();
    res.send(<pre>${JSON.stringify(settings, null, 2)}</pre>);
  } catch (err) {
    res.send('Erreur lors de la récupération des paramètres.');
  }
});

module.exports = router;

