javascriptCopierModifierconst db = require('../config/database');

const getDefaultData = () => {
  return new Promise((resolve, reject) => {
    // Récupération des paramètres de limites depuis la table settings
    const settingsQuery = `
      SELECT key, value FROM settings
      WHERE key IN ('most_recent_limit', 'most_opened_limit')
    `;
    db.all(settingsQuery, [], (err, settings) => {
      if (err) {
        return reject(new Error('Erreur lors de la récupération des paramètres.'));
      }

      const limits = Object.fromEntries(settings.map(setting => [setting.key, parseInt(setting.value, 10)]));
      const mostRecentLimit = limits.most_recent_limit || 3;
      const mostOpenedLimit = limits.most_opened_limit || 10;

      // Récupération des données les plus récentes
      const recentQuery = `
        SELECT * FROM datas
        ORDER BY dateAdd DESC
        LIMIT ?
      `;
      db.all(recentQuery, [mostRecentLimit], (err, recentData) => {
        if (err) {
          return reject(new Error('Erreur lors de la récupération des données récentes.'));
        }

        // Récupération des données les plus ouvertes
        const openedQuery = `
          SELECT d.*, s.openCount
          FROM datas d
          LEFT JOIN dataStats s ON d.id = s.dataId
          ORDER BY s.openCount DESC
          LIMIT ?
        `;
        db.all(openedQuery, [mostOpenedLimit], (err, mostOpenedData) => {
          if (err) {
            return reject(new Error('Erreur lors de la récupération des données les plus ouvertes.'));
          }

          resolve({
            recent: recentData,
            mostOpened: mostOpenedData
          });
        });
      });
    });
  });
};

