const addData = ({ name, data, filePath, tags }) => {
  return new Promise((resolve, reject) => {
    db.run(
      `INSERT INTO datas (name, data) VALUES (?, ?)`,
      [name, data || null],
      function (err) {
        if (err) {
          console.error('Erreur lors de l\'insertion de la donnée :', err.message);
          return reject(err);
        }

        const dataId = this.lastID;

        // Ajout des tags associés
        const tagPromises = tags.map((tag) => {
          return new Promise((tagResolve, tagReject) => {
            db.run(
              `INSERT INTO dataKeyword (dataId, keywordId)
               SELECT ?, id FROM keywords WHERE keyword = ?`,
              [dataId, tag],
              (tagErr) => {
                if (tagErr) {
                  console.error(`Erreur lors de l'association du tag "${tag}" :`, tagErr.message);
                  return tagReject(tagErr);
                }
                tagResolve();
              }
            );
          });
        });

        // Résolution des promesses
        Promise.all(tagPromises)
          .then(() => {
            resolve({ id: dataId, name, data, filePath, tags });
          })
          .catch((tagErr) => {
            reject(tagErr);
          });
      }
    );
  });
};

