const db = require('../config/database');

/**
 * Récupère tous les paramètres.
 * @returns {Promise<Array>} - Liste des paramètres.
 */
const getSettings = () => {
  return new Promise((resolve, reject) => {
    const query = SELECT key, value, name FROM settings;
