      if (err) {
        console.error('Erreur lors de la récupération des paramètres :', err.message);
        reject(err);
      } else {
        resolve(rows);
      }
    });
  });
};

/**
 * Met à jour la valeur d'un paramètre.
 * @param {string} key - Clé du paramètre.
 * @param {string} value - Nouvelle valeur.
 * @returns {Promise<boolean>} - Indique si la mise à jour a réussi.
 */
const updateSettingValue = (key, value) => {
  return new Promise((resolve, reject) => {
    db.run(
      'UPDATE settings SET value = ? WHERE key = ?',
      [value, key],
      function (err) {
        if (err) {
          console.error('Erreur lors de la mise à jour du paramètre :', err.message);
          reject(err);
        } else {
          resolve(this.changes > 0); // Retourne true si une ligne a été modifiée
        }
      }
    );
  });
};

