Exemple (assurez-vous que la fonction setupAutoComplete est définie ici) :
javascriptCopierModifierexport const setupAutoComplete = (inputElement, apiUrl, onSelect) => {
  inputElement.addEventListener('input', async () => {
    const query = inputElement.value.trim();
    const suggestionsContainer = document.createElement('div');
    suggestionsContainer.classList.add('autocomplete-suggestions');
    inputElement.parentNode.appendChild(suggestionsContainer);

    if (query.length < 3) {
      suggestionsContainer.innerHTML = '';
      return;
    }

    try {
      const response = await fetch(`${apiUrl}?search=${query}`);
      const data = await response.json();
      if (data.status === 200) {
        suggestionsContainer.innerHTML = data.data
          .map(
            (keyword) =>
              `<span class="suggestion" data-keyword="${keyword.keyword}">${keyword.keyword}</span>`
          )
          .join('');
      } else {
        suggestionsContainer.innerHTML = '<p>Aucune suggestion trouvée.</p>';
      }

      suggestionsContainer.addEventListener('click', (e) => {
        if (e.target && e.target.classList.contains('suggestion')) {
          const selectedKeyword = {
            id: e.target.getAttribute('data-keyword-id'),
            keyword: e.target.getAttribute('data-keyword'),
          };
          onSelect(selectedKeyword);
          suggestionsContainer.innerHTML = ''; // Efface les suggestions après sélection
        }
      });
    } catch (err) {
      console.error('Erreur lors de la récupération des suggestions :', err);
    }
  });
};




